import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const Dashboard = () => {
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    assigned: 0,
    inProgress: 0,
    onHold: 0,
    closed: 0,
  });
  const [userRole, setUserRole] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const role = localStorage.getItem('role');
    setUserRole(role);
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const { data } = await API.get('/complaints/stats');
      setStats(data);
    } catch (err) {
      console.error('Error fetching stats:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    navigate('/');
  };

  const handleNavigate = (path) => navigate(path);

  const isSuperAdmin = userRole === 'SuperAdmin';

  return (
    <div style={{ padding: '40px', background: '#0f172a', minHeight: '100vh', color: 'white' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <h1>Dashboard</h1>
        <button onClick={handleLogout} style={{ padding: '10px 20px', background: '#ef4444', border: 'none', borderRadius: '5px', color: 'white', cursor: 'pointer' }}>
          Logout
        </button>
      </div>

      {!loading && (
        <div style={{ marginBottom: '40px' }}>
          <h3 style={{ marginBottom: '20px' }}>Complaint Statistics</h3>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '20px' }}>
            <StatCard label="Total Complaints" value={stats.total} color="#38bdf8" />
            <StatCard label="Pending" value={stats.pending} color="#f59e0b" />
            <StatCard label="Assigned" value={stats.assigned} color="#8b5cf6" />
            <StatCard label="In-Progress" value={stats.inProgress} color="#3b82f6" />
            <StatCard label="On-Hold" value={stats.onHold} color="#ef4444" />
            <StatCard label="Completed" value={stats.closed} color="#10b981" />
          </div>
        </div>
      )}

      {isSuperAdmin && (
        <>
          <h3 style={{ marginBottom: '20px', marginTop: '40px' }}>Master Screens (SuperAdmin Only)</h3>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px', marginBottom: '40px' }}>
            <NavButton label="Department Master" onClick={() => handleNavigate('/department')} />
            <NavButton label="Programme Master" onClick={() => handleNavigate('/programme')} />
            <NavButton label="Block Master" onClick={() => handleNavigate('/block')} />
            <NavButton label="Room Master" onClick={() => handleNavigate('/room')} />
            <NavButton label="Role Master" onClick={() => handleNavigate('/role')} />
            <NavButton label="User Management" onClick={() => handleNavigate('/users')} />
          </div>
        </>
      )}

      <h3 style={{ marginBottom: '20px' }}>Complaint Management</h3>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px' }}>
        {(isSuperAdmin || userRole === 'User') && <NavButton label="Raise Complaint" onClick={() => handleNavigate('/raise-complaint')} />}
        <NavButton label="View Complaints" onClick={() => handleNavigate('/complaints')} />
        {isSuperAdmin && <NavButton label="Generate Report" onClick={() => handleNavigate('/report')} primary />}
      </div>
    </div>
  );
};

const StatCard = ({ label, value, color }) => (
  <div style={{ background: 'rgba(255,255,255,0.05)', border: `2px solid ${color}`, padding: '20px', borderRadius: '10px', textAlign: 'center' }}>
    <div style={{ fontSize: '0.9rem', color: '#94a3b8', marginBottom: '10px' }}>{label}</div>
    <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color }}>{value}</div>
  </div>
);

const NavButton = ({ label, onClick, primary = false }) => (
  <button
    onClick={onClick}
    style={{ padding: '20px', background: primary ? 'linear-gradient(to right, #38bdf8, #818cf8)' : 'rgba(255,255,255,0.1)', border: primary ? 'none' : '1px solid #334155', borderRadius: '10px', color: 'white', fontSize: '1rem', fontWeight: 'bold', cursor: 'pointer', transition: 'all 0.3s' }}
    onMouseEnter={e => (e.target.style.background = primary ? 'linear-gradient(to right, #0ea5e9, #6366f1)' : 'rgba(255,255,255,0.15)')}
    onMouseLeave={e => (e.target.style.background = primary ? 'linear-gradient(to right, #38bdf8, #818cf8)' : 'rgba(255,255,255,0.1)')}
  >
    {label}
  </button>
);

export default Dashboard;
